mapper.select:
select b.id, b.data_id, b.raw_data
from ${tableName} a
         inner join sys_sec_idata b on a.id = b.data_id
where b.parent_id = #{parentId}
  and b.env = #{env}

select count(1) record_count, sum(case when valid_pass = '0' then 1 else 0 end) error_count
from ${tableName} a
         inner join sys_sec_idata b on a.id = b.data_id
where b.parent_id = #{parentId}
  and b.env = #{env}
